<div class="page-head"><div><h2>Employee Loans</h2><p class="muted">Loan request, installment tracking, payroll deduction, and audit trail.</p></div></div>
<div class="grid grid-2"><div class="card"><h3>Create Loan</h3><form method="post" action="<?=url('/loans/store')?>"><?=csrf_field()?><div class="form-row"><div><label>Employee</label><select name="employee_id"><?php foreach($employees as $e): ?><option value="<?=e($e['id'])?>"><?=e($e['full_name'])?></option><?php endforeach; ?></select></div><div><label>Loan No</label><input name="loan_no" required></div><div><label>Principal</label><input name="principal" type="number" step="0.01"></div><div><label>Installment</label><input name="installment" type="number" step="0.01"></div></div><br><button class="btn btn-primary">Save Loan</button></form></div><div class="card"><h3>Report</h3><div class="grid grid-3"><div><div class="muted">Loans</div><div class="stat"><?=count($rows)?></div></div><div><div class="muted">Outstanding</div><div class="stat"><?=money_id(array_sum(array_map(fn($r)=>(float)$r['outstanding'],$rows)))?></div></div><div><div class="muted">Active</div><div class="stat"><?=count(array_filter($rows,fn($r)=>$r['status']==='active'))?></div></div></div></div></div><br>
<div class="card"><h3>List Data & Workflow</h3><table class="table"><tr><th>Employee</th><th>No</th><th>Principal</th><th>Outstanding</th><th>Installment</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['employee_name'])?></td><td><?=e($r['loan_no'])?></td><td><?=money_id($r['principal'])?></td><td><?=money_id($r['outstanding'])?></td><td><?=money_id($r['installment'])?></td><td><?=e($r['status'])?></td><td><form method="post" action="<?=url('/loans/update')?>" style="display:flex;gap:6px"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($r['id'])?>"><input name="outstanding" type="number" step="0.01" value="<?=e($r['outstanding'])?>"><select name="status"><option>active</option><option>closed</option><option>cancelled</option></select><button class="btn btn-light">Update</button></form></td></tr><?php endforeach; ?></table></div>
